 38 |     private fun enforceMaxVolume() {
 39 |         val am = getSystemService(Context.AUDIO_SERVICE) as AudioManager
 40 |         val nm = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
 41 |         
 42 |         if (LockManager.isWhisperMode(applicationContext)) {
 43 |                             val elapsed = LockManager.getWhisperElapsed(applicationContext)
 44 |                 val steps = LockManager.getWhisperSteps(applicationContext)
 45 |                 
 46 |                 if (elapsed > 60000 && steps < 30) {
 47 |                 val maxVol = am.getStreamMaxVolume(AudioManager.STREAM_ALARM)
 48 |                 val currentVol = am.getStreamVolume(AudioManager.STREAM_ALARM)
 49 | 
 50 |                 // 1. Force DND Off
 51 |                 if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
 52 |                     if (nm.isNotificationPolicyAccessGranted) {
 53 |                         nm.setInterruptionFilter(NotificationManager.INTERRUPTION_FILTER_ALL)
 54 |                     }
 55 |                 }
 56 |                 
 57 |                 // 2. Force Volume Max with Logic Logging
 58 |                 if (currentVol < maxVol) {
 59 |                     DebugLogger.log("AUDIO_ENFORCE", "RESTRICTED: $currentVol/$maxVol. Snapping to MAX.")
 60 |                     am.setStreamVolume(AudioManager.STREAM_ALARM, maxVol, 0)
 61 |                 } else {
 62 |                     // This log proves the recursion guard is working
 63 |                     DebugLogger.log("AUDIO_GUARD", "PASSED: $currentVol/$maxVol. No change needed.")
 64 |                 }
 65 |             }
 66 |         }
 67 |     }
