 83 |     override fun onSensorChanged(event: SensorEvent?) {
 84 |         val ctx = applicationContext
 85 |         
 86 |         // 1. SHAKE DETECTION (Requires holding Volume Up)
 87 |         if (event?.sensor?.type == Sensor.TYPE_ACCELEROMETER) {
 88 |             if (!LockManager.isVolumeUpHeld) {
 89 |                 shakeTimestamps.clear()
 90 |                 return
 91 |             }
 92 | 
 93 |             val x = event.values[0]
 94 |             val y = event.values[1]
 95 |             val z = event.values[2]
 96 |             val magnitude = Math.sqrt((x * x + y * y + z * z).toDouble()).toFloat()
 97 | 
 98 |             if (magnitude > shakeThreshold) {
 99 |                 val now = System.currentTimeMillis()
100 |                 
101 |                 // Debounce: Only count one shake every 150ms to ensure directional change
102 |                 if (now - lastShakeTimestamp > 150) {
103 |                     shakeTimestamps.addLast(now)
104 |                     lastShakeTimestamp = now
105 |                     
106 |                     while (shakeTimestamps.isNotEmpty() && now - shakeTimestamps.first > shakeWindow) {
107 |                         shakeTimestamps.removeFirst()
108 |                     }
109 | 
110 |                     DebugLogger.log("EXORCIST", "Distinct Shake Detected (${shakeTimestamps.size}/3)")
111 |                     if (shakeTimestamps.size >= 3) {
112 |                         shakeTimestamps.clear()
113 |                         if (!LockManager.isWhisperMode(ctx)) {
114 |                             DebugLogger.log("EXORCIST", "TRIGGER: Conditions met. Launching Protocol.")
115 |                             LockManager.startWhisperMode(ctx, isReflex = true)
116 |                             val vibrator = getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
117 |                             vibrator.vibrate(longArrayOf(0, 500, 200, 500), -1)
118 |                             
