120 |                             putExtra("BLOCK_TYPE", "WHISPER_PROTOCOL")
121 |                             addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP)
122 |                         }
123 |                         startActivity(intent)
124 |                         }
125 |                     }
126 |                 }
127 |             }
128 |         }
129 | 
130 |         // 2. STEP DETECTION (ENFORCEMENT)
131 |         if (event?.sensor?.type == Sensor.TYPE_STEP_DETECTOR) {
132 |             if (LockManager.isWhisperMode(ctx)) {
133 |                 LockManager.addWhisperStep(ctx)
134 |                 
