136 |                 if (steps >= 30) {
137 |                     DebugLogger.log("EXORCIST", "Release Authorized. Steps: $steps")
138 |                     LockManager.stopWhisperMode(ctx)
139 |                 }
140 |             }
141 |         }
142 |     }
